# ============================================================
# Real Bash Commands in PowerShell
# Place in: $PROFILE
# ============================================================
# 
# 戦略: Git for Windows に同梱されている MSYS2/GNU coreutils を
#        PowerShell の PATH に追加し、本物の bash コマンドを使う。
#
# 前提: Git for Windows がインストール済み
#   - 未インストールなら: winget install Git.Git
#   - または MSYS2 単体: winget install MSYS2.MSYS2
# ============================================================

# --- 1. GNU ユーティリティの PATH 追加 ---

# Git for Windows のパスを自動検出
$GitPaths = @(
    "${env:ProgramFiles}\Git\usr\bin"
    "${env:ProgramFiles(x86)}\Git\usr\bin"
    "${env:LOCALAPPDATA}\Programs\Git\usr\bin"
    "C:\Program Files\Git\usr\bin"
)
# MSYS2 単体インストール
$Msys2Paths = @(
    "C:\msys64\usr\bin"
    "${env:USERPROFILE}\scoop\apps\msys2\current\usr\bin"
)

$GnuBinPath = $null
foreach ($p in ($GitPaths + $Msys2Paths)) {
    if (Test-Path $p) { $GnuBinPath = $p; break }
}

if ($GnuBinPath) {
    # PowerShell 組み込みエイリアスを除去 (GNU コマンドと衝突するもの)
    $conflicting = @(
        'cat','cp','curl','diff','echo','kill','ls','man','mkdir',
        'mount','mv','ps','rm','rmdir','sleep','sort','tee','type','wget','write'
    )
    foreach ($a in $conflicting) {
        Remove-Item "Alias:$a" -Force -ErrorAction SilentlyContinue
    }

    # GNU bin を PATH の先頭に追加 (PowerShell 組み込みより優先)
    $env:PATH = "$GnuBinPath;$env:PATH"

    Write-Host "GNU coreutils loaded from: $GnuBinPath" -ForegroundColor DarkGreen
} else {
    Write-Warning @"
GNU coreutils not found. Install one of:
  winget install Git.Git        (recommended, includes 200+ GNU commands)
  winget install MSYS2.MSYS2    (full MSYS2 environment)
  scoop install git             (via Scoop)
"@
}

# --- 2. bash 自体も使えるように ---
$BashExe = if ($GnuBinPath) { Join-Path (Split-Path $GnuBinPath) "bin\bash.exe" } else { $null }
if (-not $BashExe -or -not (Test-Path $BashExe)) {
    $altBash = @(
        "${env:ProgramFiles}\Git\bin\bash.exe"
        "C:\msys64\usr\bin\bash.exe"
    )
    foreach ($b in $altBash) {
        if (Test-Path $b) { $BashExe = $b; break }
    }
}

# bash -c "command" をショートカットで使えるように
function bash {
    param([Parameter(ValueFromRemainingArguments)]$Args)
    if ($BashExe -and (Test-Path $BashExe)) {
        & $BashExe @Args
    } else {
        Write-Error "bash.exe not found"
    }
}

# bash スクリプトを直接実行するヘルパー
function Run-Bash {
    param([string]$Script)
    if ($BashExe) { & $BashExe -c $Script }
    else { Write-Error "bash.exe not found" }
}
Set-Alias -Name 'sh' -Value 'Run-Bash'

# --- 3. PowerShell では提供されない bash 固有コマンドの補完 ---

# ナビゲーション (GNU にないので PowerShell 側で定義)
function .. { Set-Location .. }
function ... { Set-Location ../.. }
function .... { Set-Location ../../.. }

# ll / la は GNU ls のオプションとして使う
function ll { ls.exe -lah --color=auto @args }
function la { ls.exe -A --color=auto @args }

# export (bash 構文を PowerShell で使えるように)
function export {
    param([Parameter(ValueFromRemainingArguments)][string[]]$Assignments)
    foreach ($a in $Assignments) {
        if ($a -match '^(\w+)=(.*)$') {
            Set-Item "env:$($Matches[1])" $Matches[2]
        }
    }
}

# source (. file 相当)
function source {
    param([string]$File)
    if ($File -match '\.(ps1|psm1)$') { . $File }
    else { Run-Bash ". '$File'" }
}

# which (GNU which がなければ PowerShell で補完)
if (-not (Get-Command 'which.exe' -ErrorAction SilentlyContinue)) {
    function which { (Get-Command $args[0] -ErrorAction SilentlyContinue).Source }
}

# --- 4. ls にカラー出力を強制 ---
function ls { ls.exe --color=auto @args }

# --- 5. man fallback ---
if (-not (Get-Command 'man.exe' -ErrorAction SilentlyContinue)) {
    function man {
        param([string]$Cmd)
        try { & $Cmd --help 2>&1 | head -50 }
        catch { Get-Help $Cmd }
    }
}

# --- 6. Bash 風キーバインド ---
Set-PSReadLineKeyHandler -Key 'Ctrl+l' -Function ClearScreen
Set-PSReadLineKeyHandler -Key 'Ctrl+d' -Function DeleteCharOrExit
Set-PSReadLineKeyHandler -Key 'Ctrl+a' -Function BeginningOfLine
Set-PSReadLineKeyHandler -Key 'Ctrl+e' -Function EndOfLine
Set-PSReadLineKeyHandler -Key 'Ctrl+w' -Function BackwardDeleteWord
Set-PSReadLineKeyHandler -Key 'Ctrl+r' -Function ReverseSearchHistory
Set-PSReadLineKeyHandler -Key 'Ctrl+u' -Function BackwardDeleteLine
Set-PSReadLineKeyHandler -Key 'Ctrl+k' -Function ForwardDeleteLine

# --- 7. 使えるコマンド一覧表示 ---
function Show-GnuCommands {
    if ($GnuBinPath) {
        $cmds = Get-ChildItem "$GnuBinPath\*.exe" | Select-Object -ExpandProperty BaseName | Sort-Object
        Write-Host "Available GNU commands ($($cmds.Count)):" -ForegroundColor Cyan
        $cmds | Format-Wide -AutoSize
    }
}

