    if ($GnuBinPath) {
        $cmds = Get-ChildItem "$GnuBinPath\*.exe" | Select-Object -ExpandProperty BaseName | Sort-Object
        Write-Host "Available GNU commands ($($cmds.Count)):" -ForegroundColor Cyan
        $cmds | Format-Wide -AutoSize
    }
}

