using System.Runtime.InteropServices;
public class Win32 {
    [DllImport("user32.dll")]
    public static extern bool ShowWindow(IntPtr hWnd, int nCmdShow);
    [DllImport("kernel32.dll")]
    public static extern IntPtr GetConsoleWindow();
    [DllImport("kernel32.dll", CharSet = CharSet.Unicode, SetLastError = true)]
    public static extern uint GetLongPathName(
        string shortPath, StringBuilder longPath, uint bufferLength);
}
"@
# SW_MAXIMIZE = 3 でウィンドウを最大化
[Win32]::ShowWindow([Win32]::GetConsoleWindow(), 3) | Out-Null

# TEMP/TMPパスの8.3短縮名(例: 000025~1)を長いパス名に変換する
# (~を含むパスがNode.jsやbashでEINVALエラーを起こすのを防ぐ)
function Resolve-LongPath([string]$ShortPath) {
    $buf = New-Object System.Text.StringBuilder 512
    $len = [Win32]::GetLongPathName($ShortPath, $buf, $buf.Capacity)
    if ($len -gt 0) { return $buf.ToString() }
    return $ShortPath
}
if ($env:TEMP -match '~') { $env:TEMP = Resolve-LongPath $env:TEMP }
if ($env:TMP  -match '~') { $env:TMP  = Resolve-LongPath $env:TMP }

